import React from 'react';
import ArticleCard from '../components/ArticleCard';

const HeadlinesPage = () => {
    const [activeCategory, setActiveCategory] = React.useState('All');

    // Mock data for the masonry layout
    const articles = [
        {
            id: 1,
            title: "SpaceX Launches Next Gen Starship",
            category: "Space",
            imageUrl: "https://images.unsplash.com/photo-1517976487492-5750f3195933?auto=format&fit=crop&q=80&w=800",
            size: "large"
        },
        {
            id: 2,
            title: "Minimalist Architecture Trends for 2025",
            category: "Design",
            imageUrl: "https://images.unsplash.com/photo-1486718448742-163732cd1544?auto=format&fit=crop&q=80&w=800",
            size: "medium"
        },
        {
            id: 3,
            title: "The Economics of Coffee: A Global Crisis",
            category: "Economy",
            imageUrl: "https://images.unsplash.com/photo-1447933601403-0c60e017bc32?auto=format&fit=crop&q=80&w=800",
            size: "small"
        },
        {
            id: 4,
            title: "Why Vinyl Records are Making a Comeback",
            category: "Music",
            imageUrl: "https://images.unsplash.com/photo-1603048588665-791ca8aea617?auto=format&fit=crop&q=80&w=800",
            size: "medium"
        },
        {
            id: 5,
            title: "Electric Vehicles Hit New Sales Record",
            category: "Auto",
            imageUrl: "https://images.unsplash.com/photo-1593941707882-a5bba14938c7?auto=format&fit=crop&q=80&w=800",
            size: "medium"
        },
        {
            id: 6,
            title: "Hidden Gems of the Mediterranean",
            category: "Travel",
            imageUrl: "https://images.unsplash.com/photo-1523906834658-6e24ef2386f9?auto=format&fit=crop&q=80&w=800",
            size: "large"
        },
        {
            id: 7,
            title: "Meditation and Brain Health",
            category: "Health",
            imageUrl: "https://images.unsplash.com/photo-1506126613408-eca07ce68773?auto=format&fit=crop&q=80&w=800",
            size: "small"
        },
        {
            id: 8,
            title: "The Rise of Vertical Farming",
            category: "Agriculture",
            imageUrl: "https://images.unsplash.com/photo-1530836369250-ef72a3f5cda8?auto=format&fit=crop&q=80&w=800",
            size: "medium"
        }
    ];

    const categories = ['All', 'Space', 'Design', 'Economy', 'Music', 'Auto', 'Travel', 'Health', 'Agriculture'];

    const filteredArticles = activeCategory === 'All'
        ? articles
        : articles.filter(article => article.category === activeCategory);

    return (
        <div className="min-h-screen bg-cream-50 px-6 py-12">
            <div className="max-w-7xl mx-auto">
                <header className="mb-12 text-center">
                    <h1 className="font-serif text-6xl md:text-7xl font-black mb-4">HEADLINES</h1>
                    <p className="text-xl font-bold text-gray-500">Today's most important stories, curated for you.</p>
                </header>

                {/* Category Tabs */}
                <div className="flex overflow-x-auto pb-4 mb-8 gap-4 justify-start md:justify-center scrollbar-hide">
                    {categories.map((category) => (
                        <button
                            key={category}
                            onClick={() => setActiveCategory(category)}
                            className={`
                                whitespace-nowrap px-6 py-2 font-bold text-lg border-b-4 transition-all
                                ${activeCategory === category
                                    ? 'border-soft-blue-500 text-black'
                                    : 'border-transparent text-gray-400 hover:text-gray-600 hover:border-gray-200'}
                            `}
                        >
                            {category.toUpperCase()}
                        </button>
                    ))}
                </div>

                {/* Masonry Layout using CSS Columns */}
                <div className="columns-1 md:columns-2 lg:columns-3 gap-8 space-y-8">
                    {filteredArticles.map((article) => (
                        <div key={article.id} className="break-inside-avoid mb-8">
                            <ArticleCard
                                id={article.id}
                                title={article.title}
                                category={article.category}
                                imageUrl={article.imageUrl}
                                size={article.size} // Note: size prop in ArticleCard might need adjustment for pure CSS columns if we want true masonry flow, but visual style works.
                            />
                        </div>
                    ))}
                </div>

                <div className="mt-20 text-center">
                    <button className="font-bold text-xl border-b-4 border-black pb-1 hover:text-soft-blue-600 hover:border-soft-blue-600 transition-colors">
                        LOAD MORE STORIES
                    </button>
                </div>
            </div>
        </div>
    );
};

export default HeadlinesPage;
